const projects = $('Fetch Active Projects').all().map(i => i.json);
const tasks = $('Fetch Pending Tasks').all().map(i => i.json);

const now = new Date();
const weekEnd = new Date(now);
weekEnd.setDate(now.getDate() + 7);

function getProp(props, key, type) {
  const p = props?.[key];
  if (!p) return null;
  if (type === 'title') return p.title?.[0]?.plain_text || null;
  if (type === 'text') return p.rich_text?.[0]?.plain_text || null;
  if (type === 'select') return p.select?.name || null;
  if (type === 'multi_select') return (p.multi_select || []).map(s => s.name);
  if (type === 'date') return p.date?.start || null;
  if (type === 'relation') return (p.relation || []).map(r => r.id);
  return null;
}

const phaseDateMap = {
  'Pre-Kickoff': 'date_pre_kickoff', 'Kickoff': 'date_kickoff',
  'Initial Test': 'date_initial_test', 'Initial Report': 'date_initial_report',
  'Presentation': 'date_presentation', 'Patching': 'date_patching',
  'Retest': 'date_retest', 'Retest Report': 'date_retest_report'
};

const activeProjects = projects.filter(p => {
  const phase = getProp(p.properties, 'current_phase', 'select');
  return phase && phase !== 'Retest Report';
});

const projectPlans = activeProjects.map(proj => {
  const props = proj.properties;
  const projectId = getProp(props, 'project_id', 'title');
  const projectName = getProp(props, 'project_name', 'text');
  const clientName = getProp(props, 'client_name', 'text');
  const currentPhase = getProp(props, 'current_phase', 'select');
  const methodology = getProp(props, 'methodology', 'select');

  // Get all upcoming dates within next 7 days
  const upcomingDeadlines = [];
  Object.entries(phaseDateMap).forEach(([phase, field]) => {
    const d = getProp(props, field, 'date');
    if (d) {
      const date = new Date(d);
      if (date >= now && date <= weekEnd) {
        const daysUntil = Math.ceil((date - now) / (1000 * 60 * 60 * 24));
        upcomingDeadlines.push({ phase, date: d, daysUntil });
      }
    }
  });

  // Get tasks for this project
  const projTasks = tasks.filter(t => {
    const rel = t.properties?.project_id?.relation || [];
    return rel.some(r => r.id === proj.id);
  });

  const pendingTasks = projTasks.filter(t => {
    const status = getProp(t.properties, 'task_status', 'select');
    return status !== 'Done';
  }).map(t => ({
    name: getProp(t.properties, 'task_name', 'text'),
    status: getProp(t.properties, 'task_status', 'select'),
    due: getProp(t.properties, 'due_date', 'date'),
    pentesterId: (t.properties?.pentester_id?.relation || [])[0]?.id
  }));

  return { projectId, projectName, clientName, currentPhase, methodology, upcomingDeadlines, pendingTasks };
});

const weekNumber = Math.ceil((now - new Date(now.getFullYear(), 0, 1)) / (7 * 24 * 60 * 60 * 1000));

return [{ json: { projectPlans, weekNumber, weekStart: now.toISOString().split('T')[0], weekEnd: weekEnd.toISOString().split('T')[0] } }];

const planText = $input.first().json.text || 'Weekly plan tidak dapat dibuat.';
const weekData = $('Aggregate Weekly Data').first().json;
const weekNum = weekData.weekNumber;
const weekStart = weekData.weekStart;

return [{ json: { planText, weekNum, weekStart, chatId: $vars.PENTESTER_GROUP_CHAT_ID } }];
